import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { configuracaoEmpresa, colaboradores as mockColaboradores } from '../data/mockData';

type ViewMode = 'login' | 'register' | 'confirm' | 'forgot';

const Login: React.FC = () => {
  const navigate = useNavigate();
  const { 
    setIsAuthenticated, setColaboradores, setEmpresa, setUser, 
    setIsConfigured, setEmpresas, setEmpresaId 
  } = useContext(AppContext);

  const [mode, setMode] = useState<ViewMode>('login');
  const [email, setEmail] = useState('admin@salya.com');
  const [password, setPassword] = useState('admin123');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');
  const [confirmCode, setConfirmCode] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [errorString, setErrorString] = useState('');

  const executeLogin = (userEmail: string, userName: string) => {
    setIsAuthenticated(true);
    setUser({ email: userEmail, name: userName });

    if (userEmail === 'admin@salya.com') {
      const empresaComId = { ...configuracaoEmpresa, id: 1 };
      setEmpresas([empresaComId]);
      setEmpresaId(1);
      setEmpresa(empresaComId);
      setColaboradores(mockColaboradores.map(c => ({ ...c, empresaId: 1 })));
      setIsConfigured(true);
      navigate('/processamento');
    } else {
      setEmpresas([]);
      setEmpresaId(null);
      setEmpresa(null);
      setColaboradores([]);
      setIsConfigured(false);
      navigate('/configuracoes');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (email && password) {
      executeLogin(email, 'Administrador');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setErrorString('');
    if (password !== confirmPassword) {
      setErrorString('As palavras-passe não coincidem.');
      return;
    }
    if (name && email && password) {
      setMode('confirm');
    }
  };

  const handleConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (confirmCode) {
      setMode('login');
      setEmail('');
      setPassword('');
      setName('');
      setConfirmPassword('');
      setConfirmCode('');
    }
  };

  const handleForgotPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setMode('login');
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50 dark:bg-slate-950">
      <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-[32px] shadow-2xl overflow-hidden border border-slate-100 dark:border-slate-800">
        <div className="p-10 flex flex-col items-center">
          <div className="mb-8 flex flex-col items-center">
             <img src="/logo.png" alt="SALYA" className="w-16 h-16 object-contain mb-4" />
             <h1 className="text-2xl font-black text-primary tracking-tighter uppercase">SALYA</h1>
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-[4px] mt-1">Smarter Payroll</p>
          </div>

          {mode === 'login' && (
            <form className="w-full space-y-6" onSubmit={handleLogin}>
              <div className="space-y-4">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Palavra-passe</label><input type={showPassword ? 'text' : 'password'} value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
              </div>
              <div className="flex justify-end"><button type="button" onClick={() => setMode('forgot')} className="text-[10px] font-black text-primary uppercase tracking-widest hover:underline">Recuperar Acesso</button></div>
              <button type="submit" className="w-full py-5 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-primary/20 active:scale-95 transition-all">Entrar no Sistema</button>
              <p className="text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">Novo aqui? <button type="button" onClick={() => setMode('register')} className="text-primary hover:underline">Criar Conta</button></p>
            </form>
          )}

          {mode === 'register' && (
            <form className="w-full space-y-5" onSubmit={handleRegister}>
              {errorString && <div className="p-3 bg-red-50 text-red-500 rounded-xl text-[10px] font-black uppercase text-center border border-red-100">{errorString}</div>}
              <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome do Administrador</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
              <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail Corporativo</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Confirmar</label><input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
              </div>
              <button type="submit" className="w-full py-5 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-xs mt-4">Registar Agora</button>
              <button type="button" onClick={() => setMode('login')} className="w-full text-center text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Já tenho conta</button>
            </form>
          )}

          {mode === 'confirm' && (
            <form className="w-full space-y-6 pt-4" onSubmit={handleConfirm}>
              <div className="text-center mb-6">
                 <h2 className="text-lg font-black uppercase text-slate-800 dark:text-white">Confirmação</h2>
                 <p className="text-xs text-slate-400 font-bold mt-1">Código enviado para o e-mail</p>
              </div>
              <input type="text" maxLength={6} value={confirmCode} onChange={(e) => setConfirmCode(e.target.value)} className="w-full text-center text-4xl font-black tracking-[10px] py-6 bg-slate-50 dark:bg-slate-800 border-none rounded-3xl outline-none focus:ring-2 focus:ring-primary dark:text-white" placeholder="000000" required />
              <button type="submit" className="w-full py-5 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-xs">Validar Acesso</button>
            </form>
          )}

          {mode === 'forgot' && (
            <form className="w-full space-y-6 pt-4" onSubmit={handleForgotPassword}>
              <div className="text-center mb-6">
                 <h2 className="text-lg font-black uppercase text-slate-800 dark:text-white">Recuperar Senha</h2>
                 <p className="text-xs text-slate-400 font-bold mt-1">Introduza o seu e-mail de registo</p>
              </div>
              <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white" required /></div>
              <button type="submit" className="w-full py-5 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-xs">Enviar Link</button>
              <button type="button" onClick={() => setMode('login')} className="w-full text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">Voltar para Login</button>
            </form>
          )}
        </div>
      </div>
      <p className="mt-12 text-[9px] font-black text-slate-300 uppercase tracking-[6px]">SALYA Ecosystem © 2026</p>
    </div>
  );
};

export default Login;
